module top_module(
    X,
    obf_A
);output reg [3:0] X;
    input [3:0] obf_A;

    // Voltage supply signals
    supply1 KAPWR;
    supply1 VPWR ;
    supply0 VGND ;
    supply1 VPB  ;
    supply0 VNB  ;

    always @ (obf_A) begin
        X = (2**3 * obf_A[3]) + (2**2 * obf_A[2]) + (2**1 * obf_A[1]) + (2**0 * obf_A[0]);
    end

endmodule
